function createStyleOptions(count) {
  return [
    { value: "custom", label: "Custom", selected: true },
    ...createNumberedOptions("Style", count),
  ];
}

function createNumberedOptions(labelPrefix, count, selectedValue = "") {
  return Array.from({ length: count }, (_, index) => {
    const value = String(index + 1);

    return {
      value,
      label: `${labelPrefix} ${value}`,
      selected: value === selectedValue,
    };
  });
}

function copyToClipboard(value) {
  if (navigator.clipboard) {
    navigator.clipboard.writeText(value).catch(() => {
      copyToClipboardFallback(value);
    });
    return;
  }

  copyToClipboardFallback(value);
}

function copyToClipboardFallback(value) {
  const textarea = document.createElement("textarea");
  textarea.value = value;
  textarea.setAttribute("readonly", "");
  textarea.style.position = "fixed";
  textarea.style.opacity = "0";
  document.body.appendChild(textarea);
  textarea.select();
  document.execCommand("copy");
  textarea.remove();
}

function escapeHtml(value) {
  return String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}
